def topbar() -> None:
    user = current_user()
    if user is None:
        return
    user_role_label = role_label(user)
    brand_html = '<span>충남119 </span><span class="brand-ai">A</span><span> ss </span><span class="brand-ai">I</span><span> st</span>'
    left, mode_col, request_col, logout_col = st.columns([6.6, 1.2, 1.2, 1.1])
    with left:
        st.markdown(
            f"""
            <div class="topbar">
                <div>
                    <b>{brand_html}</b> <span class="badge">{esc(user_role_label)}</span>
                    <div class="official-mini">{APP_SUBTITLE} · 충남소방본부 제공 공식 AI가 아닌 비공식 참고 서비스</div>
                </div>
                <div class="muted">{datetime.now().strftime('%Y-%m-%d %H:%M')}</div>
            </div>
            """,
            unsafe_allow_html=True,
        )
    with mode_col:
        if user.get("role") == "admin":
            admin_mode = bool(st.session_state.get("admin_mode", False))
            next_label = "일반사용자" if admin_mode else "관리자"
            if st.button(next_label, key="topbar_admin_mode_toggle", use_container_width=True):
                st.session_state["admin_mode"] = not admin_mode
                st.rerun()
        else:
            st.markdown("<div style='height:50px;'></div>", unsafe_allow_html=True)
    with request_col:
        if user.get("role") != "admin":
            if st.button("권한 요청", key="top_admin_request_open_btn", use_container_width=True):
                st.session_state["show_top_admin_request"] = not st.session_state.get("show_top_admin_request", False)
        else:
            st.markdown("<div style='height:50px;'></div>", unsafe_allow_html=True)
    with logout_col:
        if st.button("로그아웃", key="topbar_logout", use_container_width=True):
            logout()
    if st.session_state.get("show_top_admin_request", False):
        with st.container():
            st.markdown("<div class='section-card'><h3>관리자 권한 요청</h3>", unsafe_allow_html=True)
            top_admin_request_panel(user)
            st.markdown("</div>", unsafe_allow_html=True)


def privacy_notice_confirmed() -> bool:
    """개인정보·책임 안내 확인 여부를 세션 기준으로 판단한다."""
    return st.session_state.get("show_login_privacy_notice") is False


def render_login_privacy_notice() -> None:
    """로그인 직후 매번 개인정보·책임 안내만 표시한다."""
    if privacy_notice_confirmed():
        return
    st.markdown(
        """
        <div class="login-privacy-alert">
            <b>개인정보 입력 금지 및 책임 안내</b><br>
            질문, 자료 등록 요청, 권한 요청 시 개인정보, 민감정보, 보안자료 및 비공개 내부자료를 입력하지 마십시오.<br><br>
            AI 답변의 정확성, 최신성, 완전성 및 특정 업무처리의 적법성은 보장되지 않습니다.<br><br>
            입력한 내용과 이를 바탕으로 한 최종 판단 및 업무처리의 책임은 사용자 본인에게 있습니다.<br><br>
            최종 업무처리 전에는 반드시 담당 부서 및 공식 자료를 확인하시기 바랍니다.
        </div>
        """,
        unsafe_allow_html=True,
    )
    if st.button(
        "개인정보 입력 금지 및 책임 안내를 확인하였으며, 입력 내용 및 최종 업무처리에 대한 책임이 사용자 본인에게 있음을 확인했습니다.",
        key="confirm_login_privacy_notice",
        type="primary",
        use_container_width=True,
    ):
        st.session_state["show_login_privacy_notice"] = False
        st.rerun()


def main() -> None:
    st.set_page_config(page_title=APP_NAME, page_icon=PAGE_ICON, layout="wide", initial_sidebar_state="expanded")
    init_storage()
    normalize_existing_data()
    inject_css()
    if not current_user():
        login_page()
        return
    check_session()
    if "show_login_privacy_notice" not in st.session_state:
        st.session_state["show_login_privacy_notice"] = True
    if "admin_mode" not in st.session_state:
        st.session_state["admin_mode"] = False
    if not privacy_notice_confirmed():
        render_login_privacy_notice()
        return
    topbar()
    menu = sidebar_menu()
    if menu == "홈":
        home_page()
    elif menu == "법령 자료실":
        resources_page()
    elif menu == "자료 등록 요청":
        resource_request_page()
    elif menu == "관리자":
        admin_page()

